// ─────────────────────────────────────────────────
// HireFlow — Weighted Scoring Engine
// Skills 50% | Experience 30% | Education 20%
// ─────────────────────────────────────────────────

const data = $input.first().json.output;
const jd = $('⚙️ Set JD Config').first().json;
const webhookBody = $('New Application Received').first().json.body || {};

// Extract scores
const skillsScore    = Number(data.skills_match_score)    || 0;
const expScore       = Number(data.experience_match_score) || 0;
const eduScore       = Number(data.education_match_score)  || 0;

// Weighted final score
const finalScore = Math.round(
  (skillsScore * 0.50) +
  (expScore    * 0.30) +
  (eduScore    * 0.20)
);

// Routing decision
let status        = 'rejected';
let statusEmoji   = '❌';
let statusLabel   = 'Not Selected';
if (finalScore >= 75) {
  status      = 'accepted';
  statusEmoji = '✅';
  statusLabel = 'Shortlisted for Interview';
} else if (finalScore >= 50) {
  status      = 'waitlisted';
  statusEmoji = '⏳';
  statusLabel = 'Placed on Waitlist';
}

// Candidate info — prefer LLM extracted, fall back to webhook payload
const candidateName  = data.candidate_name  || webhookBody.candidate_name  || 'Candidate';
const candidateEmail = data.candidate_email || webhookBody.candidate_email || '';
const candidatePhone = data.candidate_phone || 'Not provided';

// Prepare clean string arrays for storage
const matchedSkillsStr  = (data.matched_skills || []).join(', ')  || 'None extracted';
const missingSkillsStr  = (data.missing_skills || []).join(', ')  || 'None';
const strengthsStr      = (data.top_strengths  || []).join(' | ') || 'None extracted';
const redFlagsStr       = (data.red_flags      || []).length > 0
                          ? (data.red_flags).join(' | ')
                          : 'None identified';

return [{
  json: {
    // Candidate info
    candidate_name:    candidateName,
    candidate_email:   candidateEmail,
    candidate_phone:   candidatePhone,
    years_experience:  data.years_experience  || 0,
    education_level:   data.education_level   || 'Not extracted',

    // JD context
    job_title:         jd.job_title,
    required_skills:   jd.required_skills,
    company_name:      jd.company_name,
    hr_email:          jd.hr_email,
    hr_slack_channel:  jd.hr_slack_channel,

    // Scores
    skills_score:      skillsScore,
    experience_score:  expScore,
    education_score:   eduScore,
    final_score:       finalScore,

    // Outcome
    status:            status,
    status_emoji:      statusEmoji,
    status_label:      statusLabel,

    // Analysis
    matched_skills:    matchedSkillsStr,
    missing_skills:    missingSkillsStr,
    strengths:         strengthsStr,
    red_flags:         redFlagsStr,
    bias_check_passed: data.bias_check_passed !== false,
    detailed_reasoning: data.detailed_reasoning || '',

    // Meta
    scored_at:         new Date().toISOString()
  }
}];

